class Solution:
    def calculateRowHeights(self, heights: List[int]) -> List[int):
        result = [] # Initialize an empty array to store the result
        total_height = 0 # Initialize the total height to 0

        for height in heights:
            total_height += height # Calculate the total height
            result.append(total_height) # Append the total height into the result array

        return result # Return the result array
